mapper.select:
select e.id, e.supermarket_id, e.serial_number, e.contact_phone, e.money, e.status, e.online_status, e.sort, e.remark, e.create_time, e.update_time, s.name as supermarket_name, s.address as supermarket_address from equipment e left join supermarket_info s on e.supermarket_id = s.id
and e.serial_number like concat('%', #{param.keyword}, '%')
and e.online_status = #{param.searchIntStatus}
and e.supermarket_id = #{param.searchType}
and s.name like concat('%', #{param.searchStrField1}, '%')
and e.status = #{param.searchField1}
and e.create_time >= #{param.startTime}
and #{param.endTime} >= e.create_time
and e.delete_time is null
order by e.sort desc, e.create_time desc

